#include <bits/stdc++.h>
using namespace std;

const int N=5e5+10;

struct Node{
    int x,rank;
    long long val;
};

bool operator<(Node x,Node y){
	return x.val<y.val;
}

int n,k,son[N*32][2],siz[N*32],tot=1;
long long a[N],s[N],ans;
priority_queue<Node> q;

void Insert(long long val){
    int p=1;
    for(int i=31;i>=0;i--){
        if(!son[p][(val>>i)&1])
            son[p][(val>>i)&1]=++tot;
        p=son[p][(val>>i)&1];
        siz[p]++;
    }
}

long long query(long long val,int rank){
    int p=1;
    long long res=0;
    for(int i=31;i>=0;i--){
        if(rank<=siz[son[p][((val>>i)&1)^1]])
            p=son[p][((val>>i)&1)^1],res|=(1ll<<i);
        else
            rank-=siz[son[p][((val>>i)&1)^1]],p=son[p][(val>>i)&1];
    }
    return res;
}

int main(){
    scanf("%d%d",&n,&k);
    for(int i=1;i<=n;i++){
        scanf("%lld",&a[i]);
        s[i]=s[i-1]^a[i];
    }
    for(int i=0;i<=n;i++)
        Insert(s[i]);
    k<<=1;
    for(int i=0;i<=n;i++)
        q.push({i,1,query(s[i],1)});
    while(k--){
        Node t=q.top();
        q.pop();
        ans+=t.val;
        if(t.rank<n)
            q.push({t.x,t.rank+1,query(s[t.x],t.rank+1)});
        //printf("%lld\n",t.val);
    }
    printf("%lld",ans/2);
    return 0;
}
